module sr_latch (
    input s,
    input r,
    output reg invalid_q,
    output q_bar
);

    always @ (*) begin
        if (s && r)
            invalid_q <= 1'bx;
        else if (s)
            invalid_q <= 1'b1;
        else if (r)
            invalid_q <= 1'b0;
    end

    assign q_bar = ~invalid_q;

endmodule
